const raw = $env.UPWORK_POLL_URLS || '';
const urls = raw
  .split(/[\n,]+/)
  .map((url) => url.trim())
  .filter(Boolean);

return urls.map((pollUrl) => ({
  json: {
    poll_url: pollUrl,
    source: 'Upwork URL Poll'
  }
}));

const crypto = require('crypto');

const keywords = [
  'quant',
  'quantitative',
  'trading',
  'algorithmic',
  'machine learning',
  'ml engineer',
  'ai engineer',
  'reinforcement learning',
  'low latency',
  'crypto',
  'market microstructure',
  'python',
  'options',
  'hft',
  'infrastructure',
  'time series',
  'financial'
];

const preferredLocations = [
  'berlin',
  'germany',
  'deutschland',
  'remote',
  'europe',
  'amsterdam',
  'london',
  'switzerland',
  'zurich',
  'dubai',
  'singapore'
];

const source = items[0]?.json || {};
const jobs = Array.isArray(source.data) ? source.data : Array.isArray(source.jobs) ? source.jobs : Array.isArray(source) ? source : [];
const rows = [];

for (const job of jobs) {
  const title = job.title || '';
  const companyName = job.company_name || job.company || '';
  const location = job.location || '';
  const tags = Array.isArray(job.tags) ? job.tags.join(' ') : '';
  const description = job.description || job.text || '';
  const haystack = `${title} ${companyName} ${location} ${tags} ${description}`.toLowerCase();
  const locationText = `${location} ${job.remote ? 'remote' : ''}`.toLowerCase();

  const matchesKeyword = keywords.some((keyword) => haystack.includes(keyword));
  const matchesLocation = preferredLocations.some((place) => locationText.includes(place)) || Boolean(job.remote);

  if (!matchesKeyword || !matchesLocation) continue;

  const sourceUrl = job.url || job.slug || '';
  const key = job.slug || sourceUrl || `${companyName}|${title}|${location}`.toLowerCase();
  const externalId = crypto.createHash('sha256').update(key).digest('hex');

  rows.push({
    json: {
      external_id: externalId,
      source: 'Arbeitnow',
      source_url: sourceUrl,
      title,
      company_name: companyName,
      location,
      region: location.toLowerCase().includes('berlin') ? 'Berlin' : location.toLowerCase().includes('germany') ? 'Germany' : job.remote ? 'Remote Europe' : 'Europe',
      description,
      employment_type: job.job_types || '',
      salary_min: null,
      salary_max: null,
      currency: '',
      posted_at: job.created_at || job.date || null,
      discovered_at: new Date().toISOString(),
      stage: 'Discovered',
      raw_payload: job
    }
  });
}

const seen = new Set();
return rows.filter((row) => {
  if (seen.has(row.json.external_id)) return false;
  seen.add(row.json.external_id);
  return true;
});

const crypto = require('crypto');

const keywords = [
  'quant trading',
  'sports betting',
  'betfair',
  'trading bot',
  'algorithmic trading',
  'prediction market',
  'crypto trading',
  'machine learning finance',
  'market making',
  'python trading',
  'options trading',
  'reinforcement learning',
  'time series'
];

function decodeHtml(text) {
  return String(text || '')
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>');
}

function stripTags(text) {
  return decodeHtml(String(text || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim());
}

const rows = [];

for (const item of items) {
  const sourceItem = item.pairedItem ? $items('Build Upwork Poll URLs')[item.pairedItem.item]?.json : {};
  const pollUrl = sourceItem?.poll_url || '';
  const payload = item.json?.data || item.json?.body || item.json?.html || JSON.stringify(item.json || {});
  const html = String(payload || '');
  const linkMatches = [...html.matchAll(/href=["']([^"']*(?:\/jobs\/|~[0-9a-zA-Z]+)[^"']*)["']/g)].slice(0, 25);

  for (const match of linkMatches) {
    const rawUrl = decodeHtml(match[1]);
    const sourceUrl = rawUrl.startsWith('http') ? rawUrl : new URL(rawUrl, pollUrl).toString();
    const nearbyStart = Math.max(0, match.index - 500);
    const nearbyEnd = Math.min(html.length, match.index + 500);
    const nearby = html.slice(nearbyStart, nearbyEnd);
    const titleMatch = nearby.match(/<h[1-4][^>]*>(.*?)<\/h[1-4]>/i) || nearby.match(/title=["']([^"']+)["']/i) || nearby.match(/aria-label=["']([^"']+)["']/i);
    const title = stripTags(titleMatch?.[1] || 'Upwork freelance lead');
    const description = stripTags(nearby).slice(0, 1500);
    const haystack = (title + ' ' + description).toLowerCase();
    const matchesKeyword = keywords.some((keyword) => haystack.includes(keyword));

    if (!matchesKeyword) continue;

    const externalId = crypto.createHash('sha256').update(sourceUrl).digest('hex');

    rows.push({
      json: {
        external_id: externalId,
        source: 'Upwork URL Poll',
        source_url: sourceUrl,
        title,
        company_name: 'Upwork Client',
        location: 'Remote freelance',
        region: 'Remote freelance',
        description,
        employment_type: 'Freelance',
        salary_min: null,
        salary_max: null,
        currency: '',
        posted_at: null,
        discovered_at: new Date().toISOString(),
        stage: 'Discovered',
        raw_payload: { poll_url: pollUrl, source_url: sourceUrl, title, description }
      }
    });
  }
}

const seen = new Set();
return rows.filter((row) => {
  if (seen.has(row.json.external_id)) return false;
  seen.add(row.json.external_id);
  return true;
});

