return items.map((item) => {
  const original = item.pairedItem ? $items('Normalize + Filter Berlin/EU')[item.pairedItem.item].json : {};
  const response = item.json;
  const text = response.output_text || response.output?.[0]?.content?.[0]?.text || '{}';
  let score = {};

  try {
    score = typeof text === 'string' ? JSON.parse(text) : text;
  } catch (error) {
    score = {
      score: 0,
      priority: 'Low',
      strengths: [],
      risks: ['OpenAI response could not be parsed'],
      suggested_positioning: '',
      next_action: 'Review manually',
      reasoning: error.message
    };
  }

  return {
    json: {
      ...original,
      score: score.score,
      priority: score.priority,
      strengths: Array.isArray(score.strengths) ? score.strengths.join('\n') : String(score.strengths || ''),
      risks: Array.isArray(score.risks) ? score.risks.join('\n') : String(score.risks || ''),
      positioning: score.suggested_positioning || '',
      next_action: score.next_action || '',
      reasoning: score.reasoning || '',
      stage: Number(score.score) >= 70 ? 'Evaluated' : 'Archived'
    }
  };
});

